#include <bits/stdc++.h>
using namespace std;

int N;
int a[12];
int op[4];
long long maxV = LLONG_MIN, minV = LLONG_MAX;

void dfs(int idx, long long cur) {
    if (idx == N) {
        maxV = max(maxV, cur);
        minV = min(minV, cur);
        return;
    }
    for (int o = 0; o < 4; o++) {
        if (op[o] == 0) continue;
        op[o]--;
        long long nv;
        if (o == 0) nv = cur + a[idx];
        else if (o == 1) nv = cur - a[idx];
        else if (o == 2) nv = cur * a[idx];
        else {
            long long q = llabs(cur) / a[idx];
            nv = (cur < 0) ? -q : q;
        }
        dfs(idx + 1, nv);
        op[o]++;
    }
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> N;
    for (int i = 0; i < N; i++) cin >> a[i];
    for (int i = 0; i < 4; i++) cin >> op[i];
    dfs(1, a[0]);
    cout << maxV << '\n' << minV << '\n';
    return 0;
}
